('akamella-odekyrkogard', 'Akamella Ödekyrkogård', 'akamella-odekyrkogard', NULL, NULL, 'Sverige', 'Norrbotten', 'Kyrkogård', 3, true, false, NULL, 'En gåtfylld historia vid Muonioälven I norra Sverige, på en avlägsen plats nära Muodoslompolo, ligger Akamella Ödekyrkogård, en mystisk och övergiven begravningsplats med en lång historia.', NULL, NULL, NULL, false, false, 'published', 'wordpress_export'),
('saters-mentalsjukhus', 'Säters Mentalsjukhus', 'saters-mentalsjukhus', NULL, NULL, 'Sverige', 'Dalarna', 'Sanatorium', 3, true, false, NULL, 'Res tillbaka i tiden - Välkommen in i det övergivna Spökhuset för de Kriminellt Sjuka Välkommen in i det övergivna Spökhuset för de Kriminellt Sjuka – Säters Fasta Paviljong Stig in i historien om Säters Fasta Paviljong...', 'https://www.spokkartan.se/wp-content/uploads/2024/10/received_101562581223201101-768x1024.webp', 'spokkartan.se', NULL, false, false, 'published', 'wordpress_export'),
('alborgen', 'Alborgen', 'alborgen', NULL, NULL, 'Sverige', 'Gävleborg', 'Sanatorium', 3, true, false, NULL, 'En plats där äventyr möter det övernaturliga Alborgen, beläget i Valbo nära Gävle, är en plats som har fascinerat både spökentusiaster och äventyrslystna besökare i flera år.', NULL, NULL, NULL, false, false, 'published', 'wordpress_export'),
('bona-uppfostringsanstalt-och-mentalsjukhus', 'Bona Uppfostringsanstalt och Mentalsjukhus', 'bona-uppfostringsanstalt-och-mentalsjukhus', NULL, NULL, 'Sverige', 'Östergötland', 'Sanatorium', 3, true, false, NULL, 'En resa tillbaka i tiden Mitt i Östergötlands landsbygd ligger Bona, en plats där tiden har stannat, men vars historia fortfarande viskar genom de övergivna byggnaderna.', 'https://www.spokkartan.se/wp-content/uploads/2024/10/8-2-1024x576.jpg', 'spokkartan.se', NULL, false, false, 'published', 'wordpress_export'),
('lofstad-slott', 'Löfstad Slott', 'lofstad-slott', NULL, NULL, 'Sverige', 'Östergötland', 'Slott', 3, false, false, NULL, 'Där historien ekar i varje sal Beläget i det vackra landskapet Östergötland, strax utanför Norrköping, står Löfstad slott som ett levande monument över svensk historia och aristokratins svunna dagar.', 'https://www.spokkartan.se/wp-content/uploads/2024/10/2-1024x576.jpg', 'spokkartan.se', NULL, false, false, 'published', 'wordpress_export'),
('torpa-stenhus', 'Torpa Stenhus', 'torpa-stenhus', NULL, NULL, 'Sverige', 'Västra Götaland', 'Slott', 3, false, false, NULL, 'Torpa Stenhus, beläget i Västergötland, är ett av Sveriges mest välbevarade medeltida slott och rymmer en rik historia som sträcker sig ända tillbaka till 1400-talet.', 'https://www.spokkartan.se/wp-content/uploads/2024/11/2-4-1024x576.jpg', 'spokkartan.se', NULL, false, false, 'published', 'wordpress_export'),
('drottningholms-slott', 'Drottningholms Slott', 'drottningholms-slott', NULL, NULL, 'Sverige', 'Stockholm', 'Slott', 3, false, false, NULL, 'Drottningholms slott, beläget på Lovön utanför Stockholm, är inte bara en av Sveriges mest ståtliga och historiska byggnader – det är också en plats där övernaturliga händelser sägs pågå, även om man bor där som kungligh...', NULL, NULL, NULL, false, false, 'published', 'wordpress_export'),
('hasselby-slott', 'Hässelby Slott', 'hasselby-slott', NULL, NULL, 'Sverige', 'Stockholm', 'Slott', 3, false, false, NULL, 'Där historien lever och spökena vandrar Hässelby Slott må vara omgivet av en vacker barockträdgård och ha en historia som sträcker sig tillbaka till 1600-talet, men för dem som är intresserade av det övernaturliga är det...', 'https://www.spokkartan.se/wp-content/uploads/2024/10/2-1-1024x576.jpg', 'spokkartan.se', NULL, false, false, 'published', 'wordpress_export'),
('tynnelso-slott', 'Tynnelsö Slott', 'tynnelso-slott', NULL, NULL, 'Sverige', 'Södermanland', 'Slott', 3, false, false, NULL, 'En historisk plats för biskopar och kungar Mitt i Mälarens lugna vatten utanför Strängnäs ligger Tynnelsö slott, ett av Sveriges mest avlägsna och mystiska slott.', 'https://www.spokkartan.se/wp-content/uploads/2024/11/Spok-memes-10.jpg', 'spokkartan.se', NULL, false, false, 'published', 'wordpress_export'),
('krusenberg-herrgard', 'Krusenberg Herrgård', 'krusenberg-herrgard', NULL, NULL, 'Sverige', 'Uppsala', 'Herrgård', 3, false, false, NULL, 'Längs den gamla allén som leder mot Krusenbergs Herrgård sträcker sig skuggor över de slitna kullerstenarna och vidare mot Mälarens strandkant.', 'https://www.spokkartan.se/wp-content/uploads/2024/10/1-3-1024x576.jpg', 'spokkartan.se', NULL, false, false, 'published', 'wordpress_export'),
('sa-skapar-du-en-spokvandring', 'Så skapar du en Spökvandring', 'sa-skapar-du-en-spokvandring', NULL, NULL, 'Sverige', NULL, 'Urban', 3, false, false, NULL, 'Få fler gäster och dela med dig av historien Spökvandringar har blivit alltmer populära, och är en utmärkt möjlighet att skapa en upplevelse som besökare talar om långt efter sitt besök.', 'https://www.spokkartan.se/wp-content/uploads/2024/11/3-1024x768.jpg', 'spokkartan.se', NULL, false, false, 'published', 'wordpress_export'),
('gamla-lowenstromska-lasarettet', 'Gamla Löwenströmska Lasarettet', 'gamla-lowenstromska-lasarettet', NULL, NULL, 'Sverige', 'Stockholm', 'Övergiven', 3, false, false, NULL, 'Övergivet sjukhus med en mörk historia Gamla Löwenströmska lasarettet i Upplands Väsby är mer än en bortglömd byggnad. Bakom dess slitna fasader och krossade rutor döljer sig en historia som skakade om Sverige - mordet p...', 'https://www.spokkartan.se/wp-content/uploads/2024/11/6-scaled.jpg', 'spokkartan.se', NULL, false, false, 'published', 'wordpress_export'),
('gamla-apoteket', 'Gamla apoteket', 'gamla-apoteket', NULL, NULL, 'Sverige', 'Stockholm', NULL, 3, false, false, NULL, 'Ouppklarat mord och ouppklarade frågor I december 1913 hände något som fortfarande hemsöker Gamla apoteket i Upplands Väsby. Apotekaren Johan Hallbergson hörde plötsligt rop på hjälp från sitt apotek, men innan han hann...', NULL, NULL, NULL, false, false, 'published', 'wordpress_export'),
('bromsboda', 'Bromsboda', 'bromsboda', NULL, NULL, 'Sverige', 'Stockholm', NULL, 3, false, false, NULL, 'Barngastens rop I slutet av 1800-talet bodde en kvinna vid namn madam Jansson i Övre Runby. Hon vittnade om hur hon varje kväll hörde ett barn gråta vid Bromsboda, men hur hon än försökte lokalisera barnet fanns inget at...', NULL, NULL, NULL, false, false, 'published', 'wordpress_export'),
('gunnes-gard', 'Gunnes gård', 'gunnes-gard', NULL, NULL, 'Sverige', 'Stockholm', NULL, 3, false, false, NULL, 'Strax norr om Stockholm, i Upplands Väsby, ligger Gunnes gård. En noggrant uppbyggd rekonstruktion av en vikingagård. Gården är mer än bara en historisk plats; här finns också mystik och folktro, särskilt kring Halloween...', 'https://www.spokkartan.se/wp-content/uploads/2024/11/Vikingagarden_Gunnes_gard_2015b-1024x768.jpg', 'spokkartan.se', NULL, false, false, 'published', 'wordpress_export'),
('apertins-herrgard', 'Apertins Herrgård', 'apertins-herrgard', NULL, NULL, 'Sverige', 'Värmland', 'Herrgård', 3, false, false, NULL, 'En plats där legender och mörka historier möts Djupt i de värmländska skogarna, omgiven av bäckraviner och gammal skog, ligger Apertins Herrgård – en herrgård som både fascinerar och skrämmer med sina mörka legender och...', 'https://www.spokkartan.se/wp-content/uploads/2024/11/2-1-1024x576.jpg', 'spokkartan.se', NULL, false, false, 'published', 'wordpress_export'),
('berga-herrgard', 'Berga Herrgård', 'berga-herrgard', NULL, NULL, 'Sverige', 'Kalmar', 'Herrgård', 3, false, false, NULL, 'En av Smålands mest hemsökta platser Berga Herrgård i Högsby, Småland, är en plats fylld av både historia och mörka legender. Den pampiga herrgården, som går tillbaka till 1200-talet, har varit hem för både adelsmän och...', NULL, NULL, NULL, false, false, 'published', 'wordpress_export'),
('overgivna-platser', 'Övergivna platser', 'overgivna-platser', NULL, NULL, 'Sverige', NULL, 'Övergiven', 3, false, false, NULL, 'Urban Exploring Att utforska övergivna platser, eller ”urban exploration” (urbex), är en populär aktivitet för den äventyrliga – men det är viktigt att veta vad som gäller i Sverige för att hålla sig inom lagens gränser.', 'https://www.spokkartan.se/wp-content/uploads/2024/11/5-2-1024x576.jpg', 'spokkartan.se', NULL, false, false, 'published', 'wordpress_export'),
('ekenas-slott', 'Ekenäs Slott', 'ekenas-slott', NULL, NULL, 'Sverige', 'Östergötland', 'Slott', 3, false, false, NULL, 'Välkomna in till ett av Sveriges mest hemsökta slott Ekenäs slott, beläget i Örtomta socken i Linköpings kommun, bär på en mörk och mystisk historia som gör det till en plats fylld av sägner och skräckinjagande berättels...', 'https://www.spokkartan.se/wp-content/uploads/2024/11/11-1024x576.jpg', 'spokkartan.se', NULL, false, false, 'published', 'wordpress_export'),
('bispgarden', 'Bispgården', 'bispgarden', NULL, NULL, 'Sverige', 'Jämtland', NULL, 3, false, false, NULL, 'Spökerier i en gammal industriort Byggnaden Bispgården i Ragunda kommun må se ut som en vanlig byggnad i en norrländsk industriort, men berättelserna från dess hyresgäster vittnar om något långt mer mystiskt.', NULL, NULL, NULL, false, false, 'published', 'wordpress_export'),
('bjurholms-prastgard', 'Bjurholms Prästgård', 'bjurholms-prastgard', NULL, NULL, 'Sverige', 'Västerbotten', 'Prästgård', 3, false, false, NULL, 'En hemsökt pärla i Västerbotten Bjurholms prästgård i Västerbottens län är en plats som bär på över hundrafemtio års historia – och kanske några av dess tidigare invånare! Sedan prästgården invigdes 1853 har många passer...', NULL, NULL, NULL, false, false, 'published', 'wordpress_export'),
('blomsholm-herrgard', 'Blomsholm Herrgård', 'blomsholm-herrgard', NULL, NULL, 'Sverige', 'Västra Götaland', 'Herrgård', 3, false, false, NULL, 'En av Västsveriges mest hemsökta herrgårdar Blomsholm herrgård, belägen i Strömstad i Västra Götalands län, är en plats som fascinerar både historiker och besökare med intresse för det övernaturliga.', NULL, NULL, NULL, false, false, 'published', 'wordpress_export'),
('bogesund-slott', 'Bogesund Slott', 'bogesund-slott', NULL, NULL, 'Sverige', 'Stockholm', 'Slott', 3, false, false, NULL, 'Där förbannelser och spöken lever kvar I Vaxholm, mitt bland Stockholms skärgårds natursköna landskap, ligger Bogesunds slott – en plats som sägs bära på förbannelser och en kuslig historia.', 'https://www.spokkartan.se/wp-content/uploads/2024/11/6-2.jpg', 'spokkartan.se', NULL, false, false, 'published', 'wordpress_export'),
('borgvattnets-prastgard', 'Borgvattnets prästgård', 'borgvattnets-prastgard', NULL, NULL, 'Sverige', 'Jämtland', 'Prästgård', 3, false, false, NULL, 'Sveriges mest ökända spökhus Djupt inne i Jämtlands trolska skogar ligger en plats som fått en nästan mytisk status – Borgvattnets prästgård.', 'https://www.spokkartan.se/wp-content/uploads/2024/11/IMG_20241116_123907_938.jpg', 'spokkartan.se', NULL, false, false, 'published', 'wordpress_export'),
('broby-sanatorium', 'Broby Sanatorium', 'broby-sanatorium', NULL, NULL, 'Sverige', 'Skåne', 'Övergiven', 3, false, false, NULL, 'Broby Sanatorium – Från vårdplats till hemsökt spökhus och bostadsområde i kris Broby Sanatorium, beläget i Skåne, har länge varit en plats som bär på både tragiska berättelser och kusliga rykten.', 'https://www.spokkartan.se/wp-content/uploads/2024/11/1-2-1024x576.jpg', 'spokkartan.se', NULL, false, false, 'published', 'wordpress_export'),
('brokinds-gard', 'Brokinds gård', 'brokinds-gard', NULL, NULL, 'Sverige', 'Östergötland', 'Slott', 3, false, false, NULL, 'Ett spökslott med Barbro Påles skrämmande närvaro Bland Östergötlands natursköna landskap ligger Brokinds gård, en plats med ett historiskt arv som sträcker sig över århundraden.', 'https://www.spokkartan.se/wp-content/uploads/2024/11/4-6-1024x576.jpg', 'spokkartan.se', NULL, false, false, 'published', 'wordpress_export'),
('bromma-kyrka', 'Bromma Kyrka', 'bromma-kyrka', NULL, NULL, 'Sverige', 'Stockholm', 'Kyrka', 3, false, false, NULL, 'I Bromma, bara några kilometer från Stockholms centrum, ligger en kyrka vars historia är lika fascinerande som kuslig. Bromma kyrka, en av Sveriges äldsta rundkyrkor, har i århundraden varit föremål för berättelser om of...', NULL, NULL, NULL, false, false, 'published', 'wordpress_export'),
('gunnebo-slott', 'Gunnebo Slott', 'gunnebo-slott', NULL, NULL, 'Sverige', 'Västra Götaland', 'Slott', 3, false, false, NULL, 'Ett slott med spöken och mystik Gunnebo Slott i Mölndal är inte bara en historisk pärla – det är också en plats där det sägs att det övernaturliga har ett starkt fäste.', 'https://www.spokkartan.se/wp-content/uploads/2024/11/Johnhall.jpeg', 'spokkartan.se', NULL, false, false, 'published', 'wordpress_export'),
('frammegarden-i-skillingmark', 'Frammegården i Skillingmark', 'frammegarden-i-skillingmark', NULL, NULL, 'Sverige', 'Värmland', 'Prästgård', 3, false, false, NULL, 'Ett av Sveriges mest hemsökta spökhus? Djupt inne i de värmländska skogarna, nära gränsen till Norge, ligger Frammegården – en plats som bär på rykten om spöken, häxor och tragiska öden.', 'https://www.spokkartan.se/wp-content/uploads/2024/11/1-4-1024x768.jpg', 'spokkartan.se', NULL, false, false, 'published', 'wordpress_export'),
('kumla-herrgard', 'Kumla Herrgård', 'kumla-herrgard', NULL, NULL, 'Sverige', 'Stockholm', 'Herrgård', 3, false, false, NULL, 'Historia och spöken Mitt bland moderna villor och lummiga träd i Tyresö, Stockholms län, döljer sig Kumla Herrgård. Denna ståtliga byggnad, med anor från 1600-talet, är lika berömd för sin rika historia som för sina spök...', 'https://www.spokkartan.se/wp-content/uploads/2024/11/1-6-1024x768.jpg', 'spokkartan.se', NULL, false, false, 'published', 'wordpress_export'),
('gjeter-ya-och-siktes-ya', 'Gjeterøya och Siktesøya', 'gjeter-ya-och-siktes-ya', NULL, NULL, 'Norge', NULL, NULL, 3, false, false, NULL, 'Hemsökta platser i Langesundsfjorden Langesundsfjorden i Norge målar upp en bild av naturskön skärgård och lugna vatten, men bakom den idylliska fasaden döljer sig mörka historier och berättelser om det övernaturliga.', NULL, NULL, NULL, false, false, 'published', 'wordpress_export'),
('dolm-kirke', 'Dolm kirke', 'dolm-kirke', NULL, NULL, 'Norge', NULL, 'Kyrka', 3, false, false, NULL, 'En plats för tro, tragedier och mysterier Dolm kirke, belägen på Dolmøya i Hitra kommun, är en av de äldsta byggnaderna längs Trøndelagskusten och bär på en historia full av dramatik, tro och övernaturliga berättelser.', NULL, NULL, NULL, false, false, 'published', 'wordpress_export'),
('gamla-varket', 'Gamla Värket', 'gamla-varket', NULL, NULL, 'Norge', NULL, 'Hotell', 3, false, false, NULL, 'En historisk pärla i Sandnes med en kuslig sida Mitt i hjärtat av Sandnes, bara en minut från tågstationen och längs den charmiga gågatan Langgata, ligger GamlaVærket Gjæstgiveri & Tracteringssted.', NULL, NULL, NULL, false, false, 'published', 'wordpress_export'),
('nidarosdomen', 'Nidarosdomen', 'nidarosdomen', NULL, NULL, 'Norge', NULL, 'Kyrka', 3, false, false, NULL, 'Den spökande munken i Domen Nidarosdomen i Trondheim är inte bara en historisk byggnad. Där är också en plats där det övernaturliga sägs ha lämnat sina spår.', NULL, NULL, NULL, false, false, 'published', 'wordpress_export'),
('vang-prestegard', 'Vang Prestegård', 'vang-prestegard', NULL, NULL, 'Norge', NULL, 'Prästgård', 3, false, false, NULL, 'Vang Prestegård Ridarbu – Ett historiskt hem med övernaturliga spår Denna gamla prästgård är inte bara en plats med kulturellt och historiskt värde, utan har också blivit föremål för rykten om övernaturliga händelser som...', NULL, NULL, NULL, false, false, 'published', 'wordpress_export'),
('ovralid', 'Övralid', 'ovralid', NULL, NULL, 'Sverige', 'Östergötland', 'Herrgård', 3, false, false, NULL, 'Finns Heidenstams ande kvar i herrgården? I Västra Ny socken, på en höjd med utsikt över Vättern, står Övralid. Byggd mellan 1923 och 1925 av den svenske nobelpristagaren Verner von Heidenstam, var Övralid hans hem fram...', 'https://www.spokkartan.se/wp-content/uploads/2024/10/11-2-1024x576.jpg', 'spokkartan.se', NULL, false, false, 'published', 'wordpress_export'),
('gula-faran-i-skebacken-orebro-ett-hyreshus-med-ouppklarade-hemligheter', 'Gula Faran i Skebäcken, Örebro – ett hyreshus med ouppklarade hemligheter', 'gula-faran-i-skebacken-orebro-ett-hyreshus-med-ouppklarade-hemligheter', NULL, NULL, 'Sverige', 'Örebro', 'Spökhus', 3, false, false, NULL, 'I stadsdelen Skebäcken i Örebro står ett hyreshus som lokalbefolkningen kallar Gula Faran. Namnet kanske låter oskyldigt, men berättelserna kring huset målar upp en helt annan bild.', 'https://www.spokkartan.se/wp-content/uploads/2024/11/Gula-Faran-1024x1024.jpg', 'spokkartan.se', NULL, false, false, 'published', 'wordpress_export'),
('schillers-krog-i-alingsas', 'Schillers Krog i Alingsås', 'schillers-krog-i-alingsas', NULL, NULL, 'Sverige', 'Västra Götaland', 'Spökhus', 3, false, false, NULL, 'Hemsökelser i Alingsås På en till synes vanlig restaurang i hjärtat av Alingsås, Schillers Krog, har det genom åren rapporterats om flera märkliga och oförklarliga händelser.', NULL, NULL, NULL, false, false, 'published', 'wordpress_export'),
('katthamra-gard-haxans-hus-i-katthammarsvik', 'Katthamra Gård – Häxans Hus i Katthammarsvik', 'katthamra-gard-haxans-hus-i-katthammarsvik', NULL, NULL, 'Sverige', NULL, 'Herrgård', 3, false, false, NULL, 'På Gotlands östra kust, i Katthammarsvik, ligger Katthamra gård, en historisk herrgård med anor från 1600-talet. Men förutom sin historiska betydelse bär gården på en mörk berättelse som satt sitt prägel på platsen.', 'https://www.spokkartan.se/wp-content/uploads/2024/11/Haxa-1024x576.jpg', 'spokkartan.se', NULL, false, false, 'published', 'wordpress_export'),
('sollero-gravfalt', 'Sollerö Gravfält', 'sollero-gravfalt', NULL, NULL, 'Sverige', 'Dalarna', 'Kyrkogård', 3, false, false, NULL, 'Vikingatida gravplats och kusliga berättelser På Sollerön i Dalarna ligger ett av regionens mest betydelsefulla historiska områden – Sollerö gravfält.', NULL, NULL, NULL, false, false, 'published', 'wordpress_export'),
('hallnas-sanatorium-historia-och-spoken-mitt-ute-i-skogen', 'Hällnäs Sanatorium, historia och spöken mitt ute i skogen', 'hallnas-sanatorium-historia-och-spoken-mitt-ute-i-skogen', NULL, NULL, 'Sverige', 'Västerbotten', 'Sanatorium', 3, false, false, NULL, 'Vilsna själar och mystiska händelser Det sägs att de döda aldrig riktigt lämnat Hällnäs sanatorium. Byggt för att behandla tuberkulospatienter på 1920-talet, blev platsen för många en slutstation.', NULL, NULL, NULL, false, false, 'published', 'wordpress_export'),
('garpenbergs-slott-och-slottsfrun-som-vagrar-lamna', 'Garpenbergs Slott och slottsfrun som vägrar lämna', 'garpenbergs-slott-och-slottsfrun-som-vagrar-lamna', NULL, NULL, 'Sverige', 'Dalarna', 'Herrgård', 3, false, false, NULL, 'När man kliver in på Garpenbergs Slott i hjärtat av Dalarna är det svårt att inte känna historiens vingslag. Slottet, med anor från 1500-talet, är omgivet av mystik, minnen och – om man vågar tro berättelserna – ett och...', 'https://www.spokkartan.se/wp-content/uploads/2024/12/3-1024x576.jpg', 'spokkartan.se', NULL, false, false, 'published', 'wordpress_export'),
('snarums-kyrka', 'Snarums kyrka', 'snarums-kyrka', NULL, NULL, 'Norge', NULL, 'Kyrka', 3, false, false, NULL, 'Snarums kyrka, belägen i den idylliska Modums kommun i Norge, har en historia som sträcker sig tillbaka till medeltiden. Men förutom sin vackra arkitektur och långa traditioner har kyrkan också blivit känd för något anna...', 'https://www.spokkartan.se/wp-content/uploads/2024/12/Skarmavbild-2024-12-10-kl.-08.51.15-1024x624.png', 'spokkartan.se', NULL, false, false, 'published', 'wordpress_export'),
