('dannemora-gruvor-historiska-djup-och-overnaturliga-moten', 'Dannemora gruvor - Historiska djup och övernaturliga möten', 'dannemora-gruvor-historiska-djup-och-overnaturliga-moten', NULL, NULL, 'Sverige', 'Uppsala', NULL, 3, false, false, NULL, 'I Dannemora gruvor, där järnmalm brutits sedan 1400-talet, sägs det att något mer än bara maskiner och arbetare rör sig i de djupa schakten.', 'https://www.spokkartan.se/wp-content/uploads/2024/12/Garpenbergs-Slott-5-1024x576.jpg', 'spokkartan.se', NULL, false, false, 'published', 'wordpress_export'),
('salsta-slott', 'Salsta Slott', 'salsta-slott', NULL, NULL, 'Sverige', 'Uppsala', 'Slott', 3, false, false, NULL, 'Spöken och mysterier i det uppländska landskapet Vid första anblick kan Salsta slott framstå som vilket historiskt barockslott som helst.', 'https://www.spokkartan.se/wp-content/uploads/2024/11/Spok-memes-10.jpg', 'spokkartan.se', NULL, false, false, 'published', 'wordpress_export'),
